#include <bits/stdc++.h>
using namespace std;
int n,m,ans;
char a[105][105];
bool vis[105][105];
struct Pos{
    int x,y;
    Pos(int ax = 0, int ay = 0) {
        x=ax;
        y=ay;
    }
};
void bfs(int x,int y) {
    queue<Pos> q;
    q.push(Pos(x,y));
    while(q.size()){
        Pos now=q.front(); 
        q.pop();
        int x=now.x,y=now.y;
        if(x<1||x>n)continue;
        if(y<1||y>m)continue;
        if(a[x][y]=='0')continue;
        if(vis[x][y])continue;
        vis[x][y]=1;
        q.push(Pos(x+1,y));
        q.push(Pos(x-1,y));
        q.push(Pos(x,y+1));
        q.push(Pos(x,y-1));
    }
}
int main(void){
    cin>>n>>m;
    for(int i=1;i<=n;i++)
        for(int j=1;j<=m;j++)
            cin>>a[i][j];
    for(int x=1;x<=n;x++)
        for(int y=1;y<=m;y++)
            if(a[x][y]!='0'&&vis[x][y]==0){
                ans++;
                bfs(x,y);
            }
    cout<<ans<<endl;
    return false;
}
